    /// Store data in the keychain protected by biometric access control
    func storeBiometricProtectedCredential(account: String, data: Data, requireBiometric: Bool = true) throws {
        // Delete any existing item first
        try? deleteCredential(account: account)
        
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account,
            kSecValueData as String: data
        ]
        
        if requireBiometric {
            // Create access control that requires biometric authentication each time
            var error: Unmanaged<CFError>?
            guard let accessControl = SecAccessControlCreateWithFlags(
                kCFAllocatorDefault,
                kSecAttrAccessibleWhenPasscodeSetThisDeviceOnly,
                [.biometryCurrentSet, .privateKeyUsage],
                &error
            ) else {
                throw KeychainError.unexpectedStatus(-1)
            }
            query[kSecAttrAccessControl as String] = accessControl
        }
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            if status == errSecDuplicateItem {
                throw KeychainError.duplicateItem
            }
            throw KeychainError.unexpectedStatus(status)
        }
    }
    
