            validateSessionWithServer(session: session) { [weak self] isValid in
                guard let self = self else { return }
                DispatchQueue.main.async {
                    if isValid {
                        self.isAuthenticated = true
                        self.authState = .authenticated(userId: session.userId)
                        completion(.authenticated(userId: session.userId))
                    } else {
