    @objc private func biometricButtonTapped() {
        errorLabel.isHidden = true
        activityIndicator.startAnimating()
        
        authManager.loginWithBiometric { [weak self] result in
            DispatchQueue.main.async {
                guard let self = self else { return }
                self.activityIndicator.stopAnimating()
                
                switch result {
                case .success:
                    self.navigateToMainApp()
                    
                case .failure(let error):
                    switch error {
                    case .biometricLockout:
                        self.showPasswordLogin(message: "Biometric locked. Please use your password.")
                        self.biometricButton.isHidden = true
                        
                    case .biometricFailed:
                        // Let user try again or use password
                        self.showError("Authentication failed. Try again or use your password.")
                        
                    case .credentialNotFound:
                        self.showPasswordLogin(message: "Please sign in with your password to set up biometric login.")
                        self.biometricButton.isHidden = true
                        
                    case .serverAuthFailed:
                        self.showPasswordLogin(message: "Your stored credentials are no longer valid. Please sign in again.")
                        self.biometricButton.isHidden = true
                        // Clear invalid biometric credentials
                        self.authManager.disableBiometric()
                        
                    default:
                        self.showError(error.localizedDescription)
                    }
                }
            }
        }
    }
    
    private func showError(_ message: String) {
        errorLabel.text = message
        errorLabel.isHidden = false
    }
    
    private func navigateToMainApp() {
        // Replace with your actual navigation logic
        let mainVC = MainAppViewController()
        mainVC.modalPresentationStyle = .fullScreen
        present(mainVC, animated: true)
    }
}

// MARK: - Main App View Controller (Placeholder)

final class MainAppViewController: UIViewController {
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        
        let label = UILabel()
        label.text = "Main App - Authenticated ✓"
        label.font = .systemFont(ofSize: 24, weight: .bold)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        
        let logoutButton = UIButton(type: .system)
        logoutButton.setTitle("Log Out", for: .normal)
        logoutButton.titleLabel?.font = .systemFont(ofSize: 18)
        logoutButton.addTarget(self, action: #selector(logoutTapped), for: .touchUpInside)
        logoutButton.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(label)
        view.addSubview(logoutButton)
        
        NSLayoutConstraint.activate([
            label.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            label.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -20),
            logoutButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            logoutButton.topAnchor.constraint(equalTo: label.bottomAnchor, constant: 20)
        ])
    }
    
    @objc private func logoutTapped() {
        AuthenticationManager.shared.logout()
        dismiss(animated: true)
    }
}

